const express = require('express');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(express.json());

const client = new Client({
  node: process.env.ELASTICSEARCH_NODE || 'http://localhost:9200',
});

function isValidIndexName(index) {
  return typeof index === 'string' && /^[a-z0-9._-]+$/.test(index);
}

app.post('/search/:index', async (req, res) => {
  try {
    const index = req.params.index;
    const query = req.body && req.body.query;

    if (!isValidIndexName(index)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    if (!query || typeof query !== 'object' || Array.isArray(query)) {
      return res.status(400).json({ error: 'Invalid query DSL' });
    }

    const result = await client.search({
      index,
      body: { query }
    });

    res.json(result);
  } catch (err) {
    res.status(500).json({
      error: 'Search failed',
      message: err.message
    });
  }
});

const port = process.env.PORT || 3000;
